#!/usr/bin/env python3
from __future__ import annotations
import argparse,csv,datetime as dt,html,json
from collections import Counter
from pathlib import Path
COLS=['classification','input_identifier','input_identifier_type','expected_hostname','resolved_hostname','identity_drift_status','probe_method_success','probe_confidence','evidence_source','evidence_detail','resolved_serial','resolved_mac','follow_up_system','probe_methods_attempted','log_status','notes']
LABEL={'live_serial_confirmed':'Live Confirmed','identity_resolved':'Identity Resolved','reachable_no_serial':'Reachable, Missing Serial','unreachable_mark_off':'Unreachable, Mark Off','needs_ad_lookup':'Needs AD Lookup','needs_vision_lookup':'Needs Vision Lookup','manual_review':'Manual Review'}
ROW={'live_serial_confirmed':'good','identity_resolved':'glow','reachable_no_serial':'warn','unreachable_mark_off':'off','needs_ad_lookup':'info','needs_vision_lookup':'info','manual_review':'bad'}
def e(v): return html.escape(str(v or ''))
def rows(p):
 with open(p,newline='',encoding='utf-8-sig') as f: return list(csv.DictReader(f))
def chip(v,cls='chip'):
 v=str(v or ''); return f'<span class="{cls} {e(v).replace("_","-")}">{e(v)}</span>'
def table(rs,title,tid):
 head=''.join(f'<th>{e(c)}</th>' for c in COLS); body=[]
 for r in rs:
  cells=[]
  for c in COLS:
   v=r.get(c,'')
   if c=='probe_method_success': cells.append(f'<td>{chip(v,"method-chip")}</td>')
   elif c=='identity_drift_status': cells.append(f'<td>{chip(v,"drift-chip")}</td>')
   elif c=='probe_confidence': cells.append(f'<td>{chip(v,"confidence-chip")}</td>')
   elif c=='classification': cells.append(f'<td>{chip(LABEL.get(v,v),"status-label")}</td>')
   else: cells.append(f'<td>{e(v)}</td>')
  body.append(f'<tr class="{ROW.get(r.get("classification",""),"")}">'+''.join(cells)+'</tr>')
 return f'<section class="panel"><div class="panel-head"><h2>{e(title)}</h2><span class="count-chip">{len(rs)} rows</span></div><input class="filter" data-table="{tid}" placeholder="Filter {e(title)}"><div class="table-wrap"><table id="{tid}"><thead><tr>{head}</tr></thead><tbody>{"".join(body)}</tbody></table></div></section>'
def cards(rs):
 chosen=[r for r in rs if r.get('identity_drift_status') in ('hostname_drift','resolved_from_identifier') or r.get('probe_method_success','').startswith('ad_')][:8]
 body=[]
 for r in chosen:
  cls=ROW.get(r.get('classification',''),'info')
  body.append(f'<article class="identity-card {cls}"><div>{chip(r.get("identity_drift_status"),"drift-chip")}</div><h3>{e(r.get("resolved_hostname") or r.get("expected_hostname") or r.get("input_identifier"))}</h3><p><b>Started with:</b> {e(r.get("input_identifier"))}</p><p><b>Winning method:</b> {chip(r.get("probe_method_success"),"method-chip")}</p><p><b>Confidence:</b> {chip(r.get("probe_confidence"),"confidence-chip")}</p><p><b>Serial:</b> {e(r.get("resolved_serial"))}</p><p><b>MAC:</b> {e(r.get("resolved_mac"))}</p><p><b>Next:</b> {e(r.get("follow_up_system"))}</p></article>')
 return '<section class="panel"><div class="panel-head"><h2>Glowing Identity Evidence Cards</h2><span class="count-chip">%d cards</span></div><div class="identity-grid">%s</div></section>'%(len(body),''.join(body))
def render(rs,src):
 cc=Counter(r.get('classification','manual_review') or 'manual_review' for r in rs); mc=Counter(r.get('probe_method_success','unresolved') or 'unresolved' for r in rs); ec=Counter(r.get('evidence_source','none') or 'none' for r in rs); drift=sum(1 for r in rs if r.get('identity_drift_status')=='hostname_drift')
 metrics=f'<section class="metrics"><article class="metric"><span>Total Rows</span><strong>{len(rs)}</strong></article><article class="metric good"><span>Live Confirmed</span><strong>{cc.get("live_serial_confirmed",0)}</strong></article><article class="metric glow"><span>Identity Resolved</span><strong>{cc.get("identity_resolved",0)}</strong></article><article class="metric warn"><span>Hostname Drift</span><strong>{drift}</strong></article><article class="metric bad"><span>Manual Review</span><strong>{cc.get("manual_review",0)}</strong></article></section>'
 meth=''.join(f'<li>{chip(k,"method-chip")}<b>{v}</b></li>' for k,v in mc.items()); evid=''.join(f'<li><span>{e(k)}</span><b>{v}</b></li>' for k,v in ec.items())
 panels=f'<section class="dashboard-grid"><article class="panel"><h2>Winning Probe Methods</h2><ul>{meth}</ul></article><article class="panel"><h2>Evidence Sources</h2><ul>{evid}</ul></article><article class="panel"><h2>Operating Rule</h2><p>Resolved identity beats stale tracker identity only when the winning method and confidence are visible.</p></article></section>'
 sections=cards(rs)+''.join(table([r for r in rs if r.get('classification')==c],LABEL.get(c,c),'t_'+c) for c in ['live_serial_confirmed','identity_resolved','reachable_no_serial','unreachable_mark_off','needs_ad_lookup','needs_vision_lookup','manual_review'])
 summary=e(json.dumps({'source':str(src),'generated_at':dt.datetime.now().isoformat(timespec='seconds'),'classification_counts':dict(cc),'method_counts':dict(mc),'evidence_counts':dict(ec)},indent=2))
 return f'''<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>SysAdminSuite Identity Resolver Dashboard</title><style>:root{{--bg:#050816;--panel:#0f172a;--text:#e5e7eb;--muted:#94a3b8;--cyan:#22d3ee;--green:#22c55e;--yellow:#facc15;--red:#f87171;--violet:#a78bfa}}*{{box-sizing:border-box}}body{{margin:0;background:radial-gradient(circle at top left,rgba(34,211,238,.18),transparent 34%),linear-gradient(180deg,#020617,#0f172a,#020617);color:var(--text);font-family:Segoe UI,Arial,sans-serif}}header{{padding:26px 34px;background:rgba(2,6,23,.9);border-bottom:1px solid rgba(96,165,250,.3);box-shadow:0 0 34px rgba(34,211,238,.12)}}main{{padding:24px 34px 70px}}.notice,.panel,.metric,.identity-card{{border:1px solid rgba(96,165,250,.28);background:rgba(15,23,42,.86);border-radius:18px;padding:16px;box-shadow:0 0 28px rgba(34,211,238,.09)}}.metrics,.identity-grid,.dashboard-grid{{display:grid;grid-template-columns:repeat(auto-fit,minmax(230px,1fr));gap:14px;margin-bottom:18px}}.metric strong{{font-size:32px;display:block}}.good{{border-color:rgba(34,197,94,.55);box-shadow:0 0 28px rgba(34,197,94,.14)}}.warn{{border-color:rgba(250,204,21,.55);box-shadow:0 0 28px rgba(250,204,21,.14)}}.bad{{border-color:rgba(248,113,113,.6);box-shadow:0 0 28px rgba(248,113,113,.14)}}.glow{{border-color:rgba(167,139,250,.7);box-shadow:0 0 34px rgba(167,139,250,.22)}}.chip,.method-chip,.drift-chip,.confidence-chip,.status-label,.count-chip{{display:inline-block;border-radius:999px;padding:6px 10px;border:1px solid rgba(148,163,184,.35);background:#020617;color:var(--text);font-size:12px}}.ad-attribute-lookup,.ad-computer-lookup{{border-color:rgba(167,139,250,.7);color:#ddd6fe;box-shadow:0 0 14px rgba(167,139,250,.2)}}.identity-csv-match{{border-color:rgba(34,211,238,.65);color:#cffafe}}.manual-review-required,.conflict{{border-color:rgba(248,113,113,.7);color:#fecaca}}.hostname-drift{{border-color:rgba(250,204,21,.7);color:#fef3c7}}.resolved-from-identifier,.hostname-match,.high{{border-color:rgba(34,197,94,.65);color:#bbf7d0}}.filter{{width:100%;margin:0 0 12px;padding:10px;border-radius:12px;background:#020617;color:var(--text);border:1px solid rgba(96,165,250,.28)}}.table-wrap{{overflow:auto;max-height:580px;border:1px solid rgba(51,65,85,.8);border-radius:14px}}table{{width:100%;min-width:1700px;border-collapse:collapse}}th,td{{padding:9px 10px;border-bottom:1px solid rgba(51,65,85,.75);text-align:left;vertical-align:top;font-size:13px}}th{{position:sticky;top:0;background:#020617;color:#bfdbfe}}ul{{list-style:none;padding:0}}li{{display:flex;justify-content:space-between;gap:12px;padding:8px 0;border-bottom:1px solid rgba(51,65,85,.7)}}pre{{white-space:pre-wrap;overflow:auto;background:#020617;border-radius:12px;padding:14px}}</style></head><body><header><h1>SysAdminSuite Identity Resolver Dashboard</h1><p>Generated {e(dt.datetime.now().strftime('%Y-%m-%d %H:%M:%S'))} from {e(src)}</p></header><main><div class="notice">Local operational artifact. Do not commit dashboards or CSVs containing real hostnames, MACs, serials, locations, or tracker data.</div>{metrics}{panels}{sections}<details class="panel"><summary>Dashboard Summary JSON</summary><pre>{summary}</pre></details></main><script>for(const i of document.querySelectorAll('.filter')){{i.addEventListener('input',()=>{{const t=document.getElementById(i.dataset.table);const n=i.value.toLowerCase();for(const r of t.querySelectorAll('tbody tr'))r.style.display=r.innerText.toLowerCase().includes(n)?'':'none'}})}}</script></body></html>'''
def main():
 ap=argparse.ArgumentParser(); ap.add_argument('--input',required=True); ap.add_argument('--output',required=True); a=ap.parse_args(); rs=rows(Path(a.input)); out=Path(a.output); out.parent.mkdir(parents=True,exist_ok=True); out.write_text(render(rs,Path(a.input)),encoding='utf-8'); print(f'Wrote identity resolver dashboard: {out}')
if __name__=='__main__': main()
